using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(10, result[9]);
        Assert.AreEqual(1, result.PageIndex);
    }

    [TestMethod]
    public void Create_SecondPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(20, result[9]);
        Assert.AreEqual(2, result.PageIndex);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange - 15 items, page size 10, page 2 should have 5 items
        var source = Enumerable.Range(1, 15).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(15, result[4]);
    }

    [TestMethod]
    public void TotalPages_ExactDivision_ReturnsCorrectCount()
    {
        // Arrange - 30 items / 10 per page = 3 pages
        var source = Enumerable.Range(1, 30).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(3, result.TotalPages);
    }

    [TestMethod]
    public void TotalPages_NonExactDivision_CeilsCorrectly()
    {
        // Arrange - 31 items / 10 per page = 4 pages (ceiling)
        var source = Enumerable.Range(1, 31).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(4, result.TotalPages);
    }

    [TestMethod]
    public void TotalPages_SingleItem_ReturnsOne()
    {
        // Arrange
        var source = new[] { 42 }.AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, result.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.IsFalse(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        // Arrange - 50 items, 10 per page, page 5 is last
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 5, 10);

        // Assert
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_FirstPage_ReturnsTrue()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        // Arrange - only 5 items, page size 10 => 1 page total
        var source = Enumerable.Range(1, 5).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    [DataRow(1, 3, DisplayName = "Page size 3")]
    [DataRow(1, 7, DisplayName = "Page size 7")]
    [DataRow(1, 1, DisplayName = "Page size 1")]
    public void Create_VariousPageSizes_ReturnsCorrectItemCount(int pageIndex, int pageSize)
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex, pageSize);

        // Assert
        Assert.AreEqual(pageSize, result.Count);
    }

    [TestMethod]
    public void Create_PageSizeOne_CalculatesTotalPagesCorrectly()
    {
        // Arrange
        var source = Enumerable.Range(1, 5).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 1);

        // Assert
        Assert.AreEqual(5, result.TotalPages);
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(1, result[0]);
    }

    [TestMethod]
    public void PageIndex_StoresCorrectValue()
    {
        // Arrange
        var source = Enumerable.Range(1, 100).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 7, 10);

        // Assert
        Assert.AreEqual(7, result.PageIndex);
    }
}

