using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain the static queue to ensure test isolation
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        // Drain queue after each test
        while (_sut.ReceiveNotification() != null) { }
        _sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_ValidParameters_EnqueuesNotification()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("TestUser", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_IncludesDisplayNameInMessage()
    {
        // Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "TestUser");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("John Doe"));
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
    {
        // Act
        _sut.SendNotification("Student", "42", EntityOperation.CREATE, "TestUser");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("ID: 42"));
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, null);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_NoUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Course", "100", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
    {
        // Arrange
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, "User1");
        _sut.SendNotification("Course", "2", EntityOperation.UPDATE, "User2");
        _sut.SendNotification("Department", "3", EntityOperation.DELETE, "User3");

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.AreEqual("Student", first.EntityType);

        var second = _sut.ReceiveNotification();
        Assert.AreEqual("Course", second.EntityType);

        var third = _sut.ReceiveNotification();
        Assert.AreEqual("Department", third.EntityType);

        var empty = _sut.ReceiveNotification();
        Assert.IsNull(empty);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "has been created", DisplayName = "CREATE operation message")]
    [DataRow(EntityOperation.UPDATE, "has been updated", DisplayName = "UPDATE operation message")]
    [DataRow(EntityOperation.DELETE, "has been deleted", DisplayName = "DELETE operation message")]
    public void SendNotification_AllOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedPhrase)
    {
        // Act
        _sut.SendNotification("Student", "1", "Test Student", operation, "User");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains(expectedPhrase),
            $"Expected message to contain '{expectedPhrase}' but was '{notification.Message}'");
    }

    [TestMethod]
    public void SendNotification_CreateOperation_MessageContainsNew()
    {
        // Act
        _sut.SendNotification("Student", "1", "John", EntityOperation.CREATE, "User");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsTrue(notification.Message.StartsWith("New "));
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAt()
    {
        // Arrange
        var before = DateTime.Now.AddSeconds(-1);

        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, "User");

        // Assert
        var notification = _sut.ReceiveNotification();
        var after = DateTime.Now.AddSeconds(1);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
    }

    [TestMethod]
    public void SendNotification_MaxQueueEnforced_OldestEvicted()
    {
        // Arrange - Fill beyond the 500 cap
        for (int i = 0; i < 510; i++)
        {
            _sut.SendNotification("Student", i.ToString(), EntityOperation.CREATE, "User");
        }

        // Act - Count remaining (should be at most 500)
        int count = 0;
        while (_sut.ReceiveNotification() != null)
        {
            count++;
        }

        // Assert - Queue was capped (may be exactly 500 or slightly less due to eviction)
        Assert.IsTrue(count <= 500, $"Queue had {count} items, expected at most 500");
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - MarkAsRead is a no-op but should not throw
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(0);
        _sut.MarkAsRead(-1);
        _sut.MarkAsRead(int.MaxValue);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var service = new NotificationService();
        service.Dispose();
        // Should be safe to dispose multiple times
        service.Dispose();
    }

    [TestMethod]
    public void SendNotification_OperationStoredAsString()
    {
        // Act
        _sut.SendNotification("Instructor", "5", EntityOperation.UPDATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("UPDATE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_MessageFormat()
    {
        // Act
        _sut.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_CreateOperationWithDisplayName_MessageFormat()
    {
        // Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperationWithoutDisplayName_MessageFormat()
    {
        // Act
        _sut.SendNotification("Course", "100", EntityOperation.UPDATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("Course (ID: 100) has been updated", notification.Message);
    }
}

