using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.EntityFrameworkCore;
using System.Net;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context;
    private InstructorsController _controller;

    [TestInitialize]
    public void Setup()
    {
        var dbName = Guid.NewGuid().ToString();
        _context = TestDbContextFactory.Create(dbName);
        SeedInstructorsWithCourses(_context);
        _controller = new InstructorsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private static void SeedInstructorsWithCourses(SchoolContext context)
    {
        var dept = new Department { DepartmentID = 1, Name = "Engineering", Budget = 350000, StartDate = new DateTime(2007, 9, 1) };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course1 = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1, Enrollments = new List<Enrollment>() };
        var course2 = new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1, Enrollments = new List<Enrollment>() };
        context.Courses.AddRange(course1, course2);
        context.SaveChanges();

        var instructor1 = new Instructor
        {
            ID = 10,
            LastName = "Zheng",
            FirstMidName = "Roger",
            HireDate = new DateTime(2004, 2, 12),
            CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { CourseID = 1050, InstructorID = 10 }
            }
        };
        var instructor2 = new Instructor
        {
            ID = 11,
            LastName = "Fakhouri",
            FirstMidName = "Fadi",
            HireDate = new DateTime(2002, 7, 6),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.AddRange(instructor1, instructor2);
        context.SaveChanges();
    }

    #region Index Tests

    [TestMethod]
    public void Index_NoSelection_ReturnsViewWithInstructors()
    {
        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorId_ShowsCourses()
    {
        // Act
        var result = _controller.Index(10, null) as ViewResult;

        // Assert
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(1, model.Courses.Count());
        Assert.AreEqual("Chemistry", model.Courses.First().Title);
    }

    [TestMethod]
    public void Index_WithInstructorAndCourseId_ShowsEnrollments()
    {
        // Arrange - Add enrollment to the course
        var student = new Student { ID = 100, LastName = "Test", FirstMidName = "Student", EnrollmentDate = DateTime.Now };
        _context.Students.Add(student);
        _context.SaveChanges();

        _context.Enrollments.Add(new Enrollment { CourseID = 1050, StudentID = 100, Grade = Grade.A });
        _context.SaveChanges();

        // Act
        var result = _controller.Index(10, 1050) as ViewResult;

        // Assert
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model.Enrollments);
        Assert.AreEqual(1, model.Enrollments.Count());
    }

    #endregion

    #region Details Tests

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Details_NotFound_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithInstructor()
