using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context;
    private NotificationsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.Create();
        _controller = new NotificationsController(_context);
        // Drain the static queue to ensure test isolation
        var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        // Drain queue after test
        var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
        _controller?.Dispose();
        _context?.Dispose();
    }

    #region GetNotifications Tests

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value as dynamic;
        Assert.IsNotNull(value);
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange - Send notifications via the service
        var service = new NotificationService();
        service.SendNotification("Student", "1", "John", EntityOperation.CREATE, "Admin");
        service.SendNotification("Course", "2", "Math", EntityOperation.UPDATE, "Admin");

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
    }

    [TestMethod]
    public void GetNotifications_MoreThanTen_LimitsToTen()
    {
        // Arrange - Send 15 notifications
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Student", i.ToString(), EntityOperation.CREATE, "Admin");
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
        // The response should indicate the result is limited
        // We'll verify the remaining queue still has items
        var remaining = service.ReceiveNotification();
        Assert.IsNotNull(remaining, "There should be remaining notifications in the queue after the 10 limit");
    }

    #endregion

    #region MarkAsRead Tests

    [TestMethod]
    public void MarkAsRead_ValidId_ReturnsSuccess()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
    }

    [TestMethod]
    public void MarkAsRead_AnyId_DoesNotThrow()
    {
        // Act & Assert - MarkAsRead is a no-op but should complete successfully
        var result1 = _controller.MarkAsRead(0);
        Assert.IsNotNull(result1);

        var result2 = _controller.MarkAsRead(-1);
        Assert.IsNotNull(result2);

        var result3 = _controller.MarkAsRead(int.MaxValue);
        Assert.IsNotNull(result3);
    }

    #endregion

    #region Index Tests

    [TestMethod]
    public void Index_ReturnsView()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    #endregion
}

