namespace ContosoUniversity.Tests;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context;
    private HomeController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateWithStudents();
        _controller = new HomeController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void About_ReturnsViewWithEnrollmentDateGroups()
    {
        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        // We have students with 3 different enrollment dates: 2020-09-01, 2021-09-01, 2022-09-01
        Assert.AreEqual(3, model.Count);
    }

    [TestMethod]
    public void About_GroupsStudentsByEnrollmentDate()
    {
        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        var model = result.Model as List<EnrollmentDateGroup>;
        // 2020-09-01 has 2 students (Alexander, Alonso)
        var group2020 = model.FirstOrDefault(g => g.EnrollmentDate == new DateTime(2020, 9, 1));
        Assert.IsNotNull(group2020);
        Assert.AreEqual(2, group2020.StudentCount);

        // 2021-09-01 has 2 students (Anand, Barzdukas)
        var group2021 = model.FirstOrDefault(g => g.EnrollmentDate == new DateTime(2021, 9, 1));
        Assert.IsNotNull(group2021);
        Assert.AreEqual(2, group2021.StudentCount);

        // 2022-09-01 has 1 student (Li)
        var group2022 = model.FirstOrDefault(g => g.EnrollmentDate == new DateTime(2022, 9, 1));
        Assert.IsNotNull(group2022);
        Assert.AreEqual(1, group2022.StudentCount);
    }

    [TestMethod]
    public void About_NoStudents_ReturnsEmptyList()
    {
        // Arrange - Use empty context
        using var emptyContext = TestDbContextFactory.Create();
        using var controller = new HomeController(emptyContext);

        // Act
        var result = controller.About() as ViewResult;

        // Assert
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void Contact_ReturnsView()
    {
        // Act
        var result = _controller.Contact() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Contact_SetsViewBagMessage()
    {
        // Act
        _controller.Contact();

        // Assert
        Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
    }

    [TestMethod]
    public void Error_ReturnsView()
    {
        // Act
        var result = _controller.Error() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Unauthorized_ReturnsView()
    {
        // Act
        var result = _controller.Unauthorized() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Unauthorized_SetsViewBagMessage()
    {
        // Act
        _controller.Unauthorized();

        // Assert
        Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
    }
}

